@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-200: #d1d5da;
  --color-neutral-400: #9da7b2;
  --color-neutral-500: #778089;
  --color-neutral-600: #6b7280;
  --color-neutral-700: #545a61;
  --color-neutral-800: #353a3e;
  --color-neutral-950: #000000;
  --color-deep-cyan: #131920;
  --color-pale-blue: #e5e7eb;
  --color-teal: #05bdba;
  --color-teal-2: #14d8d4;
  --color-blue: #2036a1;
  --color-deep-teal: #0c2a2a;
  --color-blue-2: #80abfa;
  --color-blue-3: #1b205b;
  --color-teal-3: #30c8c9;
  --color-blue-4: #183dd1;
  --color-pale-teal: #d0fffe;
  --color-teal-4: #26736c;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #000000;
  --color-text-muted: #6b7280;
  --color-surface: #d1d5da;
  --color-hairline: #9da7b2;
  --color-accent: #131920;
  --color-accent-2: #e5e7eb;
  --color-accent-3: #05bdba;

  --font-sans: "Instrument Sans", ui-sans-serif, system-ui, sans-serif;
  --font-mono: "Martian Mono", ui-monospace, monospace;

  --text-xs: 0.5rem;
  --text-sm: 0.7rem;
  --text-base: 0.75rem;
  --text-lg: 0.8rem;
  --text-xl: 0.875rem;
  --text-2xl: 0.9rem;
  --text-3xl: 1rem;
  --text-4xl: 1.125rem;
  --text-5xl: 1.25rem;
  --text-6xl: 1.5rem;

  --font-weight-thin: 100;
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;
  --font-weight-extrabold: 800;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.1;
  --leading-snug: 1.2;
  --leading-normal: 1.3;
  --leading-relaxed: 1.35;
  --leading-loose: 1.5;
  --leading-looser: 1.75;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: -.025em;
  --tracking-tighter: .2px;
  --tracking-tight: .02em;
  --tracking-normal: .025em;
  --tracking-wide: .05em;

  --radius-sm: 2px;
  --radius-md: .25rem;
  --radius-lg: .375rem;
  --radius-xl: .5rem;
  --radius-2xl: .75rem;
  --radius-3xl: 1.3rem;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 2px 8px #00000026;
  --shadow-md: 0 2px 12px #0000004d;

  --breakpoint-sm: 30rem;
  --breakpoint-md: 31.25rem;
  --breakpoint-lg: 37.5rem;
  --breakpoint-xl: 40rem;
  --breakpoint-2xl: 46.875rem;
  --breakpoint-3xl: 48rem;
  --breakpoint-4xl: 67.8125rem;

  /* most-used spacing values on the source site (px): 1, 2, 4, 5, 8, 10, 12, 14, 16, 24, 32, 48 */
}

